import { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  Heart, Share2, MapPin, Ruler, Bath, Bed, Car, 
  CheckCircle, Shield, ArrowLeft, Phone, Mail, 
  Calendar, Building2, Wifi, Wind, Coffee, Dumbbell, 
  Swimmer, Lock, Camera, ChevronLeft, ChevronRight 
} from 'lucide-react';

const PropertyDetails = () => {
  const { id } = useParams();
  const [property, setProperty] = useState(null);
  const [loading, setLoading] = useState(true);
  const [currentImage, setCurrentImage] = useState(0);
  const [isFavorite, setIsFavorite] = useState(false);
  const [showEnquiryForm, setShowEnquiryForm] = useState(false);

  // Mock property data - replace with API call
  useEffect(() => {
    // Simulate API fetch
    setTimeout(() => {
      setProperty({
        id: id,
        title: "Sunrise Heights Luxury Apartments",
        slug: "sunrise-heights",
        category: "Residential",
        listingType: "Sale",
        propertyType: "Apartment",
        price: 4500000,
        originalPrice: 5500000,
        location: "Panchavati, Nashik",
        fullAddress: "Behind Indrakund Temple, Panchavati, Nashik - 422003",
        description: `Sunrise Heights offers premium 2 & 3 BHK apartments in the heart of Panchavati. 
        This residential project features modern architecture, spacious rooms, and world-class amenities. 
        The property is strategically located with easy access to schools, hospitals, and shopping centers.
        
        Each apartment is designed with Vaastu compliance and comes with premium fittings. 
        The project boasts of a grand lobby, high-speed elevators, and 24/7 security with CCTV surveillance.`,
        images: [
          "https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=1200",
          "https://images.unsplash.com/photo-1560185127-6ed189bf02f4?w=1200",
          "https://images.unsplash.com/photo-1560184897-ae75f4184ee7?w=1200",
          "https://images.unsplash.com/photo-1497366216548-37526070297c?w=1200"
        ],
        specifications: {
          bhk: 3,
          bathrooms: 2,
          area: 1450,
          furnishing: "Semi-Furnished",
          floor: "12th",
          totalFloors: 20,
          carParking: 2,
          facing: "East",
          ageOfProperty: "New Launch"
        },
        amenities: [
          { icon: Swimmer, name: "Swimming Pool" },
          { icon: Dumbbell, name: "Gymnasium" },
          { icon: Wind, name: "Club House" },
          { icon: Coffee, name: "Cafeteria" },
          { icon: Wifi, name: "High-Speed WiFi" },
          { icon: Lock, name: "24/7 Security" },
          { icon: Camera, name: "CCTV Surveillance" },
          { icon: Building2, name: "Power Backup" }
        ],
        reraVerified: true,
        governmentVerified: true,
        reraNumber: "P52100045678",
        nearbyLocations: [
          { name: "City Center Mall", distance: "2 km" },
          { name: "Railway Station", distance: "3 km" },
          { name: "Airport", distance: "15 km" },
          { name: "Hospital", distance: "1 km" }
        ]
      });
      setLoading(false);
    }, 500);
  }, [id]);

  const formatPrice = (price) => {
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    return `₹${price.toLocaleString('en-IN')}`;
  };

  const nextImage = () => {
    setCurrentImage((prev) => (prev + 1) % property.images.length);
  };

  const prevImage = () => {
    setCurrentImage((prev) => (prev - 1 + property.images.length) % property.images.length);
  };

  if (loading) {
    return (
      <div className="pt-32 min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-[#d4af37] mx-auto"></div>
          <p className="mt-4 text-gray-500">Loading property details...</p>
        </div>
      </div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="pt-24 pb-16 bg-gray-50"
    >
      <div className="container-custom">
        {/* Breadcrumb */}
        <div className="mb-6">
          <Link to="/" className="text-gray-500 hover:text-[#d4af37] text-sm">Home</Link>
          <span className="text-gray-400 mx-2">/</span>
          <Link to="/projects" className="text-gray-500 hover:text-[#d4af37] text-sm">Properties</Link>
          <span className="text-gray-400 mx-2">/</span>
          <span className="text-[#d4af37] text-sm">{property.title}</span>
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Left Column - Images Gallery */}
          <div className="lg:col-span-2">
            {/* Main Image */}
            <div className="relative bg-black rounded-2xl overflow-hidden mb-4">
              <img 
                src={property.images[currentImage]} 
                alt={property.title}
                className="w-full h-[500px] object-cover"
              />
              <button 
                onClick={prevImage}
                className="absolute left-4 top-1/2 transform -translate-y-1/2 bg-black/50 text-white p-2 rounded-full hover:bg-black/70"
              >
                <ChevronLeft size={24} />
              </button>
              <button 
                onClick={nextImage}
                className="absolute right-4 top-1/2 transform -translate-y-1/2 bg-black/50 text-white p-2 rounded-full hover:bg-black/70"
              >
                <ChevronRight size={24} />
              </button>
            </div>
            
            {/* Thumbnails */}
            <div className="flex gap-3 overflow-x-auto pb-2">
              {property.images.map((img, idx) => (
                <button
                  key={idx}
                  onClick={() => setCurrentImage(idx)}
                  className={`w-24 h-20 rounded-lg overflow-hidden border-2 transition ${
                    currentImage === idx ? 'border-[#d4af37]' : 'border-transparent'
                  }`}
                >
                  <img src={img} alt="" className="w-full h-full object-cover" />
                </button>
              ))}
            </div>

            {/* Description */}
            <div className="mt-8 bg-white rounded-2xl p-6 shadow-sm">
              <h2 className="text-2xl font-bold mb-4">Description</h2>
              <p className="text-gray-600 leading-relaxed whitespace-pre-line">{property.description}</p>
            </div>

            {/* Amenities */}
            <div className="mt-6 bg-white rounded-2xl p-6 shadow-sm">
              <h2 className="text-2xl font-bold mb-4">Amenities</h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {property.amenities.map((amenity, idx) => (
                  <div key={idx} className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
                    <amenity.icon className="text-[#d4af37]" size={20} />
                    <span className="text-gray-700">{amenity.name}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Nearby Locations */}
            <div className="mt-6 bg-white rounded-2xl p-6 shadow-sm">
              <h2 className="text-2xl font-bold mb-4">Nearby Locations</h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {property.nearbyLocations.map((place, idx) => (
                  <div key={idx} className="text-center p-3 bg-gray-50 rounded-lg">
                    <p className="font-semibold">{place.name}</p>
                    <p className="text-sm text-gray-500">{place.distance}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Right Column - Property Info & Enquiry */}
          <div>
            <div className="bg-white rounded-2xl shadow-lg p-6 sticky top-24">
              {/* Title & Price */}
              <div className="mb-4">
                <div className="flex justify-between items-start">
                  <h1 className="text-2xl font-bold text-[#0a192f]">{property.title}</h1>
                  <button 
                    onClick={() => setIsFavorite(!isFavorite)}
                    className="p-2 rounded-full hover:bg-gray-100"
                  >
                    <Heart size={24} className={isFavorite ? 'text-red-500 fill-red-500' : 'text-gray-400'} />
                  </button>
                </div>
                <div className="flex items-center gap-2 mt-2">
                  <MapPin size={16} className="text-gray-400" />
                  <p className="text-gray-500 text-sm">{property.location}</p>
                </div>
              </div>

              {/* Price */}
              <div className="mb-4">
                <span className="text-3xl font-bold text-[#d4af37]">{formatPrice(property.price)}</span>
                {property.originalPrice && (
                  <span className="text-gray-400 line-through ml-2">{formatPrice(property.originalPrice)}</span>
                )}
              </div>

              {/* Badges */}
              <div className="flex flex-wrap gap-2 mb-6">
                <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-semibold">
                  {property.listingType}
                </span>
                <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-xs font-semibold">
                  {property.category}
                </span>
                {property.reraVerified && (
                  <span className="bg-yellow-100 text-yellow-700 px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1">
                    <Shield size={12} /> RERA Verified
                  </span>
                )}
                {property.governmentVerified && (
                  <span className="bg-purple-100 text-purple-700 px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1">
                    <CheckCircle size={12} /> Govt Verified
                  </span>
                )}
              </div>

              {/* Key Specifications */}
              <div className="border-t border-b py-4 mb-6">
                <h3 className="font-semibold mb-3">Key Specifications</h3>
                <div className="grid grid-cols-2 gap-3">
                  {property.specifications.bhk > 0 && (
                    <div className="flex items-center gap-2">
                      <Bed size={18} className="text-gray-400" />
                      <span className="text-sm">{property.specifications.bhk} BHK</span>
                    </div>
                  )}
                  <div className="flex items-center gap-2">
                    <Bath size={18} className="text-gray-400" />
                    <span className="text-sm">{property.specifications.bathrooms} Bathrooms</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Ruler size={18} className="text-gray-400" />
                    <span className="text-sm">{property.specifications.area} sq.ft</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Car size={18} className="text-gray-400" />
                    <span className="text-sm">{property.specifications.carParking} Parking</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Building2 size={18} className="text-gray-400" />
                    <span className="text-sm">Floor {property.specifications.floor}/{property.specifications.totalFloors}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Calendar size={18} className="text-gray-400" />
                    <span className="text-sm">{property.specifications.furnishing}</span>
                  </div>
                </div>
              </div>

              {/* Enquiry Button */}
              <button 
                onClick={() => setShowEnquiryForm(!showEnquiryForm)}
                className="w-full bg-[#d4af37] text-[#0a192f] py-3 rounded-lg font-semibold hover:bg-opacity-90 transition mb-3"
              >
                📞 Enquire Now
              </button>

              <Link to={`/contact?property=${property.title}`}>
                <button className="w-full border-2 border-[#d4af37] text-[#d4af37] py-3 rounded-lg font-semibold hover:bg-[#d4af37] hover:text-[#0a192f] transition">
                  Request a Site Visit
                </button>
              </Link>

              {/* Quick Enquiry Form */}
              {showEnquiryForm && (
                <div className="mt-4 p-4 bg-gray-50 rounded-lg">
                  <h4 className="font-semibold mb-3">Quick Enquiry</h4>
                  <input 
                    type="text" 
                    placeholder="Your Name" 
                    className="w-full p-2 border rounded-lg mb-2"
                  />
                  <input 
                    type="tel" 
                    placeholder="Phone Number" 
                    className="w-full p-2 border rounded-lg mb-2"
                  />
                  <input 
                    type="email" 
                    placeholder="Email ID" 
                    className="w-full p-2 border rounded-lg mb-3"
                  />
                  <button className="w-full bg-[#d4af37] text-[#0a192f] py-2 rounded-lg font-semibold">
                    Submit Enquiry
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default PropertyDetails;
